// 1. Sadə intersection type
interface Person {
  name: string;
  age: number;
}
interface Role {
  role: string;
}
type Employee = Person & Role;
const employee: Employee = {
  name: "Murad",
  age: 25,
  role: "Developer"
};
console.log(employee); // Çıxış: { name: "Murad", age: 25, role: "Developer" }
// const invalidEmployee: Employee = { name: "Alice", age: 30 }; // Xəta: role xüsusiyyəti əskikdir

// 2. Type ilə intersection
type Id = { id: string };
type Details = { details: string };
type Product = Id & Details;
const product: Product = {
  id: "P001",
  details: "Wireless Mouse"
};
console.log(product); // Çıxış: { id: "P001", details: "Wireless Mouse" }

// 3. Funksiyalarda intersection type
type Printable = { print: () => string };
type Loggable = { log: () => void };
type Logger = Printable & Loggable;
const logger: Logger = {
  print: () => "Printing data",
  log: () => console.log("Logging data")
};
console.log(logger.print()); // Çıxış: Printing data
logger.log(); // Çıxış: Logging data

// 4. Intersection ilə mürəkkəb obyekt
interface ProductInfo {
  name: string;
  price: number;
}
interface StockInfo {
  inStock: boolean;
}
type FullProduct = ProductInfo & StockInfo;
const laptop: FullProduct = {
  name: "Laptop",
  price: 1200,
  inStock: true
};
console.log(`${laptop.name}: $${laptop.price}, ${laptop.inStock ? "mövcuddur" : "mövcud deyil"}`);
// Çıxış: Laptop: $1200, mövcuddur

// 5. Type narrowing ilə intersection type
interface Book {
  type: "book";
  title: string;
  pages: number;
}
interface Movie {
  type: "movie";
  title: string;
  duration: number;
}
type Media = (Book | Movie) & { id: string }; // Intersection ilə union kombinasiyası
function describeMedia(media: Media): string {
  if (media.type === "book") {
    return `${media.id}: ${media.title} - ${media.pages} pages`;
  }
  return `${media.id}: ${media.title} - ${media.duration} minutes`;
}
const book: Media = { id: "B001", type: "book", title: "TypeScript Guide", pages: 200 };
const movie: Media = { id: "M001", type: "movie", title: "Inception", duration: 148 };
console.log(describeMedia(book)); // Çıxış: B001: TypeScript Guide - 200 pages
console.log(describeMedia(movie)); // Çıxış: M001: Inception - 148 minutes

// Sadə mağaza sistemi
interface ProductInfo {
  id: string;
  name: string;
  price: number;
}
interface StockInfo {
  inStock: boolean;
  stockCount: number;
}
type FullProduct = ProductInfo & StockInfo;

function displayProduct(product: FullProduct): string {
  return `${product.name} (ID: ${product.id}): $${product.price}, ${product.inStock ? "mövcuddur" : "mövcud deyil"} (${product.stockCount} ədəd)`;
}

const laptop: FullProduct = {
  id: "P001",
  name: "Laptop",
  price: 1200,
  inStock: true,
  stockCount: 10
};
console.log(displayProduct(laptop)); // Çıxış: Laptop (ID: P001): $1200, mövcuddur (10 ədəd)

// Intersection ilə metod birləşdirmə
interface Printable {
  print: () => string;
}
interface Trackable {
  track: () => string;
}
type ProductTracker = Printable & Trackable;
const tracker: ProductTracker = {
  print: () => "Product details printed",
  track: () => "Product tracking initiated"
};
console.log(tracker.print()); // Çıxış: Product details printed
console.log(tracker.track()); // Çıxış: Product tracking initiated

